from pathlib import Path

def safe_count_visible_py_files(path: str) -> int:
    p = Path(path)
    try:
        if not p.exists() or not p.is_dir():
            return 0
        return sum(
            1
            for item in p.iterdir()
            if item.is_file()
            and not item.name.startswith('.')
            and item.suffix == '.py'
        )
    except PermissionError:
        return 0
