from pathlib import Path

def strip_anchor(p: Path) -> Path:
    # If there is an anchor, it will be the first element of parts
    if p.anchor:
        return Path(*p.parts[1:])
    return p

Two situations that still raise ValueError are: (1) different anchors, e.g., on Windows different drives like `Path('D:/data').relative_to('C:/users', walk_up=True)`; (2) mixing absolute and relative paths (different anchors), e.g., `Path('/home/user').relative_to('relative/path', walk_up=True)`. A robust approach is to try `relative_to(..., walk_up=True)` and on `ValueError` (or on Python < 3.12) fall back to `os.path.relpath()`.

Example:
```python
from pathlib import Path
import os, sys

def rel_between(start, dest):
    start_p = Path(start)
    dest_p = Path(dest)

    if sys.version_info >= (3, 12):
        try:
            return dest_p.relative_to(start_p, walk_up=True)
        except ValueError:
            # e.g., different anchors (drive letter) or abs vs rel mismatch
            return Path(os.path.relpath(dest_p, start_p))
    else:
        return Path(os.path.relpath(dest_p, start_p))
```

from pathlib import Path

def file_size_bytes(path_str: str):
    p = Path(path_str)
    try:
        return p.stat().st_size
    except FileNotFoundError:
        return None
